import { HookContext } from '@feathersjs/feathers';
import { Application, RealTimeConnection } from './declarations';

export default function(app: Application): void {
  if (typeof app.channel !== 'function') {
    return;
  }
\  app.on('connection', (connection: RealTimeConnection): void => {
    // On a new real-time connection, add it to the
    // anonymous channel
    app.channel('anonymous').join(connection);
  });

  app.on('login', (authResult: any, { connection }: any): void => {
    // connection can be undefined if there is no
    // real-time connection, e.g. when logging in via REST
    if (connection) {
      // Obtain the logged in user from the connection
      const user = connection.user;

      // The connection is no longer anonymous, remove it
      app.channel('anonymous').leave(connection);

      // Add it to the authenticated user channel
      app.channel('authenticated').join(connection);

      // Add user to their own private channel
      app.channel(`userIds/${user.id}`).join(connection);

      // Channels can be named anything and joined on any condition
      if (user.role === 'admin') {
        app.channel('admins').join(connection);
      }
    }
  });

  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  app.publish((data: any, hook: HookContext) => {
    // Here you can add event publishers to channels set up in `channels.js`
    // To publish only for a specific event use `app.publish(eventname, () => {})`

    console.log('Publishing all events to all authenticated users. See `channels.js` and https://docs.feathersjs.com/api/channels.html for more information.'); // eslint-disable-line

    // e.g. to publish all service events to all authenticated users use
    return app.channel('authenticated');
  });

  // Publish messages only to users in the same room
  app.service('messages').publish('created', (data: any) => {
    return [
      app.channel(`rooms/${data.roomId}`),
      app.channel(`userIds/${data.userId}`)
    ];
  });
}

