export class Payments implements ServiceMethods<PaymentData> {
  app: Application;
  stripe: Stripe;

  constructor(options: any, app: Application) {
    this.app = app;

    // Initialize Stripe
    const stripeKey = app.get('stripe').secretKey;
    this.stripe = new Stripe(stripeKey, {
      apiVersion: '2023-10-16'
    });
  }
\  async find(params?: Params): Promise<PaymentData[] | Paginated<PaymentData>> {
    const query = params?.query || {};
    const { $limit = 10, $skip = 0, ...filters } = query;

