  async get(id: Id, params?: Params): Promise<PaymentData> {
    // Retrieve from database and Stripe
    const payment = await this.getPaymentFromDb(id as string);

    if (!payment) {
      throw new Error('Payment not found');
    }

    // Sync with Stripe status
    if (payment.stripePaymentIntentId) {
      const intent = await this.stripe.paymentIntents.retrieve(
        payment.stripePaymentIntentId
      );

      // Update local status if different
      if (intent.status !== payment.status) {
        payment.status = this.mapStripeStatus(intent.status);
        await this.updatePaymentStatus(id as string, payment.status);
      }
    }

    return payment;
  }

  async create(data: PaymentData, params?: Params): Promise<PaymentData> {
    try {
      // Create Stripe PaymentIntent
      const paymentIntent = await this.stripe.paymentIntents.create({
        amount: Math.round(data.amount * 100), // Stripe uses cents
        currency: data.currency.toLowerCase(),
        description: data.description,
        receipt_email: data.customerEmail,
        automatic_payment_methods: {
          enabled: true
        },
        metadata: {
          internalId: data.id
        }
      });

      // Save to database
      const payment: PaymentData = {
        ...data,
        stripePaymentIntentId: paymentIntent.id,
        status: 'pending',
        createdAt: new Date()
      };

      await this.savePaymentToDb(payment);

      return payment;
    } catch (error) {
      throw new Error(`Payment creation failed: ${error.message}`);
    }
  }
\  async update(id: NullableId, data: PaymentData, params?: Params): Promise<PaymentData> {
    // Payments typically shouldn't be updated after creation
    // Only status changes are allowed
    throw new Error('Payments cannot be updated');
  }

  async patch(id: NullableId, data: Partial<PaymentData>, params?: Params): Promise<PaymentData> {
    // Allow status updates (e.g., for webhooks)
    if (id === null) {
      throw new Error('ID is required');
    }

    if (data.status) {
      await this.updatePaymentStatus(id as string, data.status);
    }

    return this.get(id, params);
  }

  async remove(id: NullableId, params?: Params): Promise<PaymentData> {
    // Payments should not be deleted
    throw new Error('Payments cannot be deleted');
  }
\  // Helper methods
  private async getPaymentFromDb(id: string): Promise<PaymentData | null> {
    // In real app: query database
    return null;
  }
\  private async savePaymentToDb(payment: PaymentData): Promise<void> {
    // In real app: save to database
