  }
\  private async updatePaymentStatus(id: string, status: string): Promise<void> {
    // In real app: update database
    console.log(`Updating payment ${id} status to ${status}`);
  }

  private mapStripeStatus(stripeStatus: string): PaymentData['status'] {
    const statusMap: Record<string, PaymentData['status']> = {
      'succeeded': 'completed',
      'processing': 'pending',
      'requires_payment_method': 'failed',
      'canceled': 'failed'
    };
    return statusMap[stripeStatus] || 'pending';
  }
\  // Webhook handler
  async handleWebhook(event: Stripe.Event): Promise<void> {
    switch (event.type) {
      case 'payment_intent.succeeded':
        const paymentIntent = event.data.object as Stripe.PaymentIntent;
        await this.updatePaymentStatus(
          paymentIntent.metadata.internalId,
          'completed'
