import {
  WebSocketGateway,
  WebSocketServer,
  SubscribeMessage,
  MessageBody,
  ConnectedSocket,
  OnGatewayConnection,
  OnGatewayDisconnect,
  WsResponse,
} from '@nestjs/websockets';
import { Server, Socket } from 'socket.io';
import { Logger, UseGuards } from '@nestjs/common';
import { WsJwtGuard } from '../auth/guards/ws-jwt.guard';
import { ChatService } from './chat.service';
import { JoinRoomDto } from './dto/join-room.dto';
import { SendMessageDto } from './dto/send-message.dto';

interface AuthenticatedSocket extends Socket {
  user: {
    id: string;
    email: string;
  };
}

@WebSocketGateway({
  namespace: 'chat',
  cors: {
    origin: '*',
  },
})
export class ChatGateway implements OnGatewayConnection, OnGatewayDisconnect {
  @WebSocketServer()
  server: Server;

  private logger: Logger = new Logger('ChatGateway');

  constructor(private chatService: ChatService) {}

  async handleConnection(client: AuthenticatedSocket) {
    this.logger.log(`Client connected: ${client.id}`);

    // Verify token from handshake
    try {
      const token = client.handshake.auth.token;
      const user = await this.chatService.verifyToken(token);
      client.user = user;
      client.join(`user_${user.id}`);

      this.server.emit('userConnected', {
        userId: user.id,
        timestamp: new Date(),
      });
    } catch (error) {
      client.disconnect();
    }
  }

  handleDisconnect(client: AuthenticatedSocket) {
    this.logger.log(`Client disconnected: ${client.id}`);

    if (client.user) {
      this.server.emit('userDisconnected', {
        userId: client.user.id,
        timestamp: new Date(),
      });
    }
  }

  @UseGuards(WsJwtGuard)
  @SubscribeMessage('join_room')
  async handleJoinRoom(
    @MessageBody() data: JoinRoomDto,
    @ConnectedSocket() client: AuthenticatedSocket,
  ) {
    const { roomId } = data;

    // Join the room
    client.join(roomId);

    // Get room history
    const messages = await this.chatService.getRoomHistory(roomId);

    // Notify others in room
    client.to(roomId).emit('user_joined', {
      userId: client.user.id,
      roomId,
      timestamp: new Date(),
    });
\    return {
      event: 'joined_room',
      data: { roomId, messages },
    };
  }

  @UseGuards(WsJwtGuard)
  @SubscribeMessage('leave_room')
  handleLeaveRoom(
    @MessageBody() data: { roomId: string },
    @ConnectedSocket() client: AuthenticatedSocket,
  ) {
    const { roomId } = data;

    client.leave(roomId);

    client.to(roomId).emit('user_left', {
      userId: client.user.id,
      roomId,
      timestamp: new Date(),
    });
\    return {
      event: 'left_room',
      data: { roomId },
    };
  }

  @UseGuards(WsJwtGuard)
  @SubscribeMessage('send_message')
  async handleMessage(
    @MessageBody() data: SendMessageDto,
    @ConnectedSocket() client: AuthenticatedSocket,
  ) {
    const { roomId, content } = data;
    const userId = client.user.id;
\    // Save message to database
    const message = await this.chatService.saveMessage({
      roomId,
      userId,
      content,
    });
\    // Broadcast to room
    this.server.to(roomId).emit('new_message', {
      id: message.id,
      content: message.content,
      userId,
      roomId,
      timestamp: message.createdAt,
    });
\    // Also send to sender's personal room
    return {
      event: 'message_sent',
      data: message,
    };
  }

  @UseGuards(WsJwtGuard)
  @SubscribeMessage('typing')
  handleTyping(
    @MessageBody() data: { roomId: string; isTyping: boolean },
    @ConnectedSocket() client: AuthenticatedSocket,
  ) {
    const { roomId, isTyping } = data;

    client.to(roomId).emit('user_typing', {
      userId: client.user.id,
      roomId,
      isTyping,
    });
  }

  // Method to emit events from other services
  notifyNewOrder(userId: string, order: any) {
    this.server.to(`user_${userId}`).emit('new_order', order);
  }

  broadcastProductUpdate(productId: string, data: any) {
    this.server.emit('product_updated', {
      productId,
      ...data,
    });
  }
}
